  1→"use client";
  2→
  3→import { useState, useRef, useCallback } from "react";
  4→import {
  5→  Container,
  6→  Heading,
  7→  Flex,
  8→  Card,
  9→  TextArea,
 10→  Button,
 11→  Text,
 12→  Badge,
 13→  Callout,
 14→  Box,
 15→  Separator,
 16→  ScrollArea,
 17→} from "@radix-ui/themes";
 18→import {
 19→  UploadIcon,
 20→  ChatBubbleIcon,
 21→  CheckCircledIcon,
 22→  CrossCircledIcon,
 23→  InfoCircledIcon,
 24→  FileIcon,
 25→  ReloadIcon,
 26→  MagicWandIcon,
 27→} from "@radix-ui/react-icons";
 28→import { useAuth } from "@/lib/auth-hooks";
 29→import { useRouter } from "next/navigation";
 30→import {
 31→  useUploadResumeMutation,
 32→  useAskAboutResumeLazyQuery,
 33→  useResumeStatusQuery,
 34→} from "@/__generated__/hooks";
 35→
 36→export const dynamic = "force-dynamic";
 37→
 38→interface ToastState {
 39→  show: boolean;
 40→  message: string;
 41→  type: "success" | "error" | "info";
 42→}
 43→
 44→const POLL_INTERVAL = 3000;
 45→const MAX_POLLS = 60;
 46→
 47→const STEPS = ["Select file", "Uploading", "Parsing PDF", "Storing", "Ready"] as const;
 48→type StepIndex = 0 | 1 | 2 | 3 | 4;
 49→
 50→const STATUS_TO_STEP: Record<string, StepIndex> = {
 51→  idle: 0,
 52→  uploading: 1,
 53→  parsing: 2,
 54→  ingesting: 3,
 55→  success: 4,
 56→  error: 0,
 57→};
 58→
 59→function ProgressStepper({ currentStep }: { currentStep: StepIndex }) {
 60→  return (
 61→    <Flex gap="1" align="center" wrap="wrap">
 62→      {STEPS.map((label, i) => {
 63→        const done = i < currentStep;
 64→        const active = i === currentStep;
 65→        return (
 66→          <Flex key={label} align="center" gap="1">
 67→            <Flex
 68→              align="center"
 69→              justify="center"
 70→              style={{
 71→                width: 22,
 72→                height: 22,
 73→                borderRadius: "50%",
 74→                background: done
 75→                  ? "var(--green-9)"
 76→                  : active
 77→                    ? "var(--accent-9)"
 78→                    : "var(--gray-4)",
 79→                color: done || active ? "white" : "var(--gray-9)",
 80→                fontSize: 11,
 81→                fontWeight: 600,
 82→                flexShrink: 0,
 83→              }}
 84→            >
 85→              {done ? "✓" : i + 1}
 86→            </Flex>
 87→            <Text
 88→              size="1"
 89→              weight={active ? "bold" : "regular"}
 90→              color={done ? "green" : active ? undefined : "gray"}
 91→              style={{ whiteSpace: "nowrap" }}
 92→            >
 93→              {label}
 94→            </Text>
 95→            {i < STEPS.length - 1 && (
 96→              <Box
 97→                style={{
 98→                  width: 16,
 99→                  height: 1,
100→                  background: done ? "var(--green-7)" : "var(--gray-5)",
101→                  flexShrink: 0,
102→                }}
103→              />
104→            )}
105→          </Flex>
106→        );
107→      })}
108→    </Flex>
109→  );
110→}
111→
112→function DropZone({
113→  file,
114→  onChange,
115→  disabled,
116→}: {
117→  file: File | null;
118→  onChange: (f: File) => void;
119→  disabled: boolean;
120→}) {
121→  const inputRef = useRef<HTMLInputElement>(null);
122→  const [dragging, setDragging] = useState(false);
123→
124→  const handleDrop = useCallback(
125→    (e: React.DragEvent) => {
126→      e.preventDefault();
127→      setDragging(false);
128→      if (disabled) return;
129→      const dropped = e.dataTransfer.files[0];
130→      if (dropped?.type === "application/pdf") onChange(dropped);
131→    },
132→    [disabled, onChange],
133→  );
134→
135→  return (
136→    <Box
137→      onClick={() => !disabled && inputRef.current?.click()}
138→      onDragOver={(e) => { e.preventDefault(); if (!disabled) setDragging(true); }}
139→      onDragLeave={() => setDragging(false)}
140→      onDrop={handleDrop}
141→      style={{
142→        border: `2px dashed ${dragging ? "var(--accent-9)" : file ? "var(--green-8)" : "var(--gray-6)"}`,
143→        borderRadius: 10,
144→        padding: "28px 20px",
145→        textAlign: "center",
146→        cursor: disabled ? "not-allowed" : "pointer",
147→        background: dragging
148→          ? "var(--accent-2)"
149→          : file
150→            ? "var(--green-2)"
151→            : "var(--gray-2)",
152→        transition: "all 0.15s ease",
153→        opacity: disabled ? 0.6 : 1,
154→      }}
155→    >
156→      <input
157→        ref={inputRef}
158→        type="file"
159→        accept="application/pdf,.pdf"
160→        style={{ display: "none" }}
161→        onChange={(e) => {
162→          const f = e.target.files?.[0];
163→          if (f) onChange(f);
164→        }}
165→        disabled={disabled}
166→      />
167→      <Flex direction="column" align="center" gap="2">
168→        {file ? (
169→          <FileIcon width={28} height={28} color="var(--green-9)" />
170→        ) : (
171→          <UploadIcon width={28} height={28} color="var(--gray-9)" />
172→        )}
173→        {file ? (
174→          <>
175→            <Text size="2" weight="medium" color="green">
176→              {file.name}
177→            </Text>
178→            <Text size="1" color="gray">
179→              {(file.size / 1024).toFixed(1)} KB — click to change
180→            </Text>
181→          </>
182→        ) : (
183→          <>
184→            <Text size="2" weight="medium">
185→              Drop your PDF here or click to browse
186→            </Text>
187→            <Text size="1" color="gray">
188→              PDF files only · max 20 pages
189→            </Text>
190→          </>
191→        )}
192→      </Flex>
193→    </Box>
194→  );
195→}
196→
197→function MarkdownAnswer({ text }: { text: string }) {
198→  // Simple markdown: bold, bullet lines, line breaks
199→  const lines = text.split("\n");
200→  return (
201→    <Flex direction="column" gap="1">
202→      {lines.map((line, i) => {
203→        const trimmed = line.trimStart();
204→        const isBullet = trimmed.startsWith("- ") || trimmed.startsWith("• ") || trimmed.startsWith("* ");
205→        const content = isBullet ? trimmed.slice(2) : line;
206→        const parts = content.split(/(\*\*[^*]+\*\*)/g);
207→        const rendered = parts.map((p, j) =>
208→          p.startsWith("**") && p.endsWith("**") ? (
209→            <Text key={j} weight="bold">{p.slice(2, -2)}</Text>
210→          ) : (
211→            <span key={j}>{p}</span>
212→          ),
213→        );
214→        if (!line.trim()) return <Box key={i} style={{ height: 6 }} />;
215→        return (
216→          <Text key={i} size="2" style={{ lineHeight: "1.65" }}>
217→            {isBullet && <span style={{ marginRight: 6 }}>•</span>}
218→            {rendered}
219→          </Text>
220→        );
221→      })}
222→    </Flex>
223→  );
224→}
225→
226→const SAMPLE_QUESTIONS = [
227→  "What are my strongest technical skills?",
228→  "Summarize my work experience",
229→  "What companies have I worked at?",
230→  "What programming languages do I know?",
231→  "What's my educational background?",
232→];
233→
234→// ── Main page ─────────────────────────────────────────────────────────────────
235→
236→function ResumePageContent() {
237→  const router = useRouter();
238→  const { user, loading, isAuthenticated } = useAuth();
239→
240→  const [resumeFile, setResumeFile] = useState<File | null>(null);
241→  const [question, setQuestion] = useState("");
242→  const [answer, setAnswer] = useState("");
243→  const [contextCount, setContextCount] = useState(0);
244→
245→  const [uploadStatus, setUploadStatus] = useState<
246→    "idle" | "uploading" | "parsing" | "ingesting" | "success" | "error"
247→  >("idle");
248→  const [queryStatus, setQueryStatus] = useState<
249→    "idle" | "querying" | "success" | "error"
250→  >("idle");
251→
252→  const [toast, setToast] = useState<ToastState>({
253→    show: false,
254→    message: "",
255→    type: "info",
256→  });
257→
258→  const [uploadedResumeId, setUploadedResumeId] = useState<string | null>(null);
259→  const [chunksCount, setChunksCount] = useState<number>(0);
260→
261→  const [uploadResumeMutation] = useUploadResumeMutation();
262→  const [askAboutResume] = useAskAboutResumeLazyQuery();
263→
264→  const userEmail = user?.email || "";
265→  const resumeKnownReady = uploadStatus === "success";
266→
267→  const { data: resumeStatusData } = useResumeStatusQuery({
268→    variables: { email: userEmail },
269→    skip: !userEmail,
270→    // Poll while processing or unknown — stop once confirmed ready
271→    pollInterval: resumeKnownReady ? 0 : 5000,
272→  });
273→
274→  const polledExists = resumeStatusData?.resumeStatus?.exists === true;
275→
276→  const resumeReady = resumeKnownReady || polledExists;
277→
278→  const existingFilename = resumeStatusData?.resumeStatus?.filename ?? null;
279→  const existingIngestedAt = resumeStatusData?.resumeStatus?.ingested_at ?? null;
280→  const displayResumeId = uploadedResumeId || resumeStatusData?.resumeStatus?.resume_id || null;
281→  const displayChunksCount = chunksCount || (resumeStatusData?.resumeStatus?.chunk_count ?? 0);
282→
283→  const showToast = (message: string, type: ToastState["type"]) => {
284→    setToast({ show: true, message, type });
285→    setTimeout(
286→      () => setToast({ show: false, message: "", type: "info" }),
287→      5000,
288→    );
289→  };
290→
291→  if (!loading && !isAuthenticated) {
292→    router.push("/sign-in");
293→    return null;
294→  }
295→
296→  if (loading) {
297→    return (
298→      <Container size="3" p="8">
299→        <Flex align="center" gap="2">
300→          <ReloadIcon style={{ animation: "spin 1s linear infinite" }} />
301→          <Text color="gray">Loading...</Text>
302→        </Flex>
303→      </Container>
304→    );
305→  }
306→
307→  const handleFileChange = (file: File) => {
308→    if (file.type !== "application/pdf") {
309→      showToast("Please upload a PDF file", "error");
310→      return;
311→    }
312→    setResumeFile(file);
313→    if (uploadStatus === "success") setUploadStatus("idle");
314→  };
315→
316→  const handleUploadResume = async () => {
317→    if (!resumeFile) {
318→      showToast("Please select a PDF file", "error");
319→      return;
320→    }
321→    if (!userEmail) {
322→      showToast("User email not found", "error");
323→      return;
324→    }
325→
326→    setUploadStatus("uploading");
327→
328→    try {
329→      // Base64-encode the PDF
330→      const arrayBuffer = await resumeFile.arrayBuffer();
331→      const base64 = btoa(
332→        new Uint8Array(arrayBuffer).reduce(
333→          (data, byte) => data + String.fromCharCode(byte),
334→          "",
335→        ),
336→      );
337→
338→      // Trigger the background task via GraphQL mutation
339→      const { data } = await uploadResumeMutation({
340→        variables: {
341→          email: userEmail,
342→          resumePdf: base64,
343→          filename: resumeFile.name,
344→        },
345→      });
346→
347→      if (!data?.uploadResume?.success) {
348→        throw new Error("Failed to start resume processing");
349→      }
350→
351→      // Task is processing in background — switch to parsing state and let
352→      // the existing resumeStatus pollInterval (5s) detect when it's ready.
353→      setUploadStatus("parsing");
354→      showToast("Processing resume in background — this page will update when ready.", "info");
355→    } catch (error) {
356→      console.error("[Resume Upload] Error:", error);
357→      setUploadStatus("error");
358→      showToast(
359→        error instanceof Error ? error.message : "Failed to upload resume",
360→        "error",
361→      );
362→      setTimeout(() => setUploadStatus("idle"), 3000);
363→    }
364→  };
365→
366→  const handleAskQuestion = async () => {
367→    if (!question.trim()) {
368→      showToast("Please enter a question", "error");
369→      return;
370→    }
371→    if (!userEmail) {
372→      showToast("User email not found", "error");
373→      return;
374→    }
375→    if (!displayResumeId && !resumeReady) {
376→      showToast("Please upload your resume first", "error");
377→      return;
378→    }
379→
380→    setQueryStatus("querying");
381→    setAnswer("");
382→
383→    try {
384→      const { data } = await askAboutResume({
385→        variables: { email: userEmail, question },
386→      });
387→
388→      const result = data?.askAboutResume;
389→      if (result?.answer) {
390→        setQueryStatus("success");
391→        setAnswer(result.answer);
392→        setContextCount(result.context_count);
393→      } else {
394→        throw new Error("No answer received");
395→      }
396→    } catch (error) {
397→      setQueryStatus("error");
398→      showToast(
399→        error instanceof Error ? error.message : "Failed to get answer",
400→        "error",
401→      );
402→    }
403→  };
404→
405→  const isUploading =
406→    uploadStatus === "uploading" ||
407→    uploadStatus === "parsing" ||
408→    uploadStatus === "ingesting";
409→
410→  const currentStep = STATUS_TO_STEP[uploadStatus] ?? 0;
411→
412→  return (
413→    <Container size="3" py="8" px="4">
414→      {/* Toast */}
415→      {toast.show && (
416→        <Box style={{ position: "fixed", top: 20, right: 20, zIndex: 1000, maxWidth: 340 }}>
417→          <Callout.Root
418→            color={toast.type === "success" ? "green" : toast.type === "error" ? "red" : "blue"}
419→          >
420→            <Callout.Icon>
421→              {toast.type === "success" ? (
422→                <CheckCircledIcon />
423→              ) : toast.type === "error" ? (
424→                <CrossCircledIcon />
425→              ) : (
426→                <InfoCircledIcon />
427→              )}
428→            </Callout.Icon>
429→            <Callout.Text>{toast.message}</Callout.Text>
430→          </Callout.Root>
431→        </Box>
432→      )}
433→
434→      <Flex direction="column" gap="6">
435→        {/* Header */}
436→        <Flex direction="column" gap="1">
437→          <Heading size="7">Resume Assistant</Heading>
438→          <Text color="gray" size="2">
439→            Upload your resume and get instant AI-powered answers about your experience
440→          </Text>
441→        </Flex>
442→
443→        {/* Upload card */}
444→        <Card>
445→          <Flex direction="column" gap="4">
446→            <Flex align="center" justify="between">
447→              <Flex align="center" gap="2">
448→                <UploadIcon />
449→                <Heading size="4">Your Resume</Heading>
450→              </Flex>
451→              {resumeReady && (
452→                <Badge color="green" variant="soft">
453→                  <CheckCircledIcon /> Ready
454→                </Badge>
455→              )}
456→            </Flex>
457→
458→            {/* Progress stepper — only when actively uploading */}
459→            {isUploading && (
460→              <ProgressStepper currentStep={currentStep} />
461→            )}
462→
463→            {/* Existing resume info */}
464→            {resumeReady && displayResumeId && (
465→              <Callout.Root color="green" variant="soft">
466→                <Callout.Icon>
467→                  <CheckCircledIcon />
468→                </Callout.Icon>
469→                <Callout.Text>
470→                  <Text weight="medium">{existingFilename || "Resume"}</Text>
471→                  {" — "}
472→                  {displayChunksCount} sections indexed
473→                  {existingIngestedAt && (
474→                    <Text color="gray">
475→                      {" · uploaded "}
476→                      {new Date(existingIngestedAt).toLocaleDateString()}
477→                    </Text>
478→                  )}
479→                </Callout.Text>
480→              </Callout.Root>
481→            )}
482→
483→            <DropZone
484→              file={resumeFile}
485→              onChange={handleFileChange}
486→              disabled={isUploading}
487→            />
488→
489→            <Flex gap="3" justify="end">
490→              <Button
491→                onClick={handleUploadResume}
492→                disabled={isUploading || !resumeFile}
493→                loading={isUploading}
494→              >
495→                <UploadIcon />
496→                {isUploading
497→                  ? uploadStatus === "uploading"
498→                    ? "Submitting…"
499→                    : uploadStatus === "parsing"
500→                      ? "Parsing PDF…"
501→                      : "Storing…"
502→                  : resumeReady
503→                    ? "Replace Resume"
504→                    : "Upload Resume"}
505→              </Button>
506→            </Flex>
507→          </Flex>
508→        </Card>
509→
510→        <Separator size="4" />
511→
512→        {/* Q&A card */}
513→        <Card>
514→          <Flex direction="column" gap="4">
515→            <Flex align="center" gap="2">
516→              <ChatBubbleIcon />
517→              <Heading size="4">Ask Questions</Heading>
518→            </Flex>
519→
520→            {!resumeReady && (
521→              <Callout.Root color="blue" variant="soft">
522→                <Callout.Icon>
523→                  <InfoCircledIcon />
524→                </Callout.Icon>
525→                <Callout.Text>Upload your resume above to enable Q&amp;A</Callout.Text>
526→              </Callout.Root>
527→            )}
528→
529→            {resumeReady && (
530→              <>
531→                <Flex gap="2" wrap="wrap">
532→                  {SAMPLE_QUESTIONS.map((sample, i) => (
533→                    <Button
534→                      key={i}
535→                      variant="soft"
536→                      size="1"
537→                      onClick={() => setQuestion(sample)}
538→                      disabled={queryStatus === "querying"}
539→                    >
540→                      {sample}
541→                    </Button>
542→                  ))}
543→                </Flex>
544→
545→                <TextArea
546→                  placeholder="Ask anything about your resume…"
547→                  value={question}
548→                  onChange={(e) => setQuestion(e.target.value)}
549→                  rows={3}
550→                  disabled={queryStatus === "querying"}
551→                  onKeyDown={(e) => {
552→                    if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) {
553→                      void handleAskQuestion();
554→                    }
555→                  }}
556→                />
557→
558→                <Flex gap="3" justify="between" align="center">
559→                  <Text size="1" color="gray">
560→                    ⌘↵ to submit
561→                  </Text>
562→                  <Button
563→                    onClick={handleAskQuestion}
564→                    disabled={queryStatus === "querying" || !question.trim()}
565→                    loading={queryStatus === "querying"}
566→                  >
567→                    <ChatBubbleIcon />
568→                    {queryStatus === "querying" ? "Thinking…" : "Ask"}
569→                  </Button>
570→                </Flex>
571→
572→                {answer && (
573→                  <Card variant="surface">
574→                    <Flex direction="column" gap="3">
575→                      <Flex justify="between" align="center">
576→                        <Text size="2" weight="bold" color="gray">
577→                          Answer
578→                        </Text>
579→                        <Badge color="gray" variant="soft" size="1">
580→                          {contextCount} sections used
581→                        </Badge>
582→                      </Flex>
583→                      <ScrollArea style={{ maxHeight: 400 }}>
584→                        <MarkdownAnswer text={answer} />
585→                      </ScrollArea>
586→                    </Flex>
587→                  </Card>
588→                )}
589→
590→                {queryStatus === "error" && (
591→                  <Callout.Root color="red">
592→                    <Callout.Icon>
593→                      <CrossCircledIcon />
594→                    </Callout.Icon>
595→                    <Callout.Text>Failed to get answer. Please try again.</Callout.Text>
596→                  </Callout.Root>
597→                )}
598→              </>
599→            )}
600→          </Flex>
601→        </Card>
602→
603→        <Separator size="4" />
604→
605→        {/* How it works */}
606→        <Card variant="surface">
607→          <Flex direction="column" gap="3">
608→            <Flex align="center" gap="2">
609→              <InfoCircledIcon />
610→              <Heading size="3">How it works</Heading>
611→            </Flex>
612→            <Flex direction="column" gap="1" ml="4">
613→              {[
614→                "Your PDF is parsed with OCR support for scanned documents",
615→                "The text is split into sections and indexed for fast search",
616→                "Questions are matched to the most relevant resume sections",
617→                "An AI model composes a precise answer from your content",
618→                "Everything is stored privately and tied to your account",
619→              ].map((step, i) => (
620→                <Text key={i} size="2" color="gray">
621→                  {i + 1}. {step}
622→                </Text>
623→              ))}
624→            </Flex>
625→          </Flex>
626→        </Card>
627→      </Flex>
628→
629→      <style>{`
630→        @keyframes spin { to { transform: rotate(360deg); } }
631→      `}</style>
632→    </Container>
633→  );
634→}
635→
636→export default function ResumePage() {
637→  return <ResumePageContent />;
638→}
