"use client";

import { useState, useRef, useCallback } from "react";
import {
  Container,
  Heading,
  Flex,
  Card,
  TextArea,
  Button,
  Text,
  Badge,
  Callout,
  Box,
  Separator,
  ScrollArea,
} from "@radix-ui/themes";
import {
  UploadIcon,
  ChatBubbleIcon,
  CheckCircledIcon,
  CrossCircledIcon,
  InfoCircledIcon,
  FileIcon,
  ReloadIcon,
  MagicWandIcon,
} from "@radix-ui/react-icons";
import { useAuth } from "@/lib/auth-hooks";
import { useRouter } from "next/navigation";
import {
  useUploadResumeMutation,
  useAskAboutResumeLazyQuery,
  useResumeStatusQuery,
} from "@/__generated__/hooks";

export const dynamic = "force-dynamic";

interface ToastState {
  show: boolean;
  message: string;
  type: "success" | "error" | "info";
}

const POLL_INTERVAL = 3000;
const MAX_POLLS = 60;

const STEPS = ["Select file", "Uploading", "Parsing PDF", "Storing", "Ready"] as const;
type StepIndex = 0 | 1 | 2 | 3 | 4;

const STATUS_TO_STEP: Record<string, StepIndex> = {
  idle: 0,
  uploading: 1,
  parsing: 2,
  ingesting: 3,
  success: 4,
  error: 0,
};

function ProgressStepper({ currentStep }: { currentStep: StepIndex }) {
  return (
    <Flex gap="1" align="center" wrap="wrap">
      {STEPS.map((label, i) => {
        const done = i < currentStep;
        const active = i === currentStep;
        return (
          <Flex key={label} align="center" gap="1">
            <Flex
              align="center"
              justify="center"
              style={{
                width: 22,
                height: 22,
                borderRadius: "50%",
                background: done
                  ? "var(--green-9)"
                  : active
                    ? "var(--accent-9)"
                    : "var(--gray-4)",
                color: done || active ? "white" : "var(--gray-9)",
                fontSize: 11,
                fontWeight: 600,
                flexShrink: 0,
              }}
            >
              {done ? "✓" : i + 1}
            </Flex>
            <Text
              size="1"
              weight={active ? "bold" : "regular"}
              color={done ? "green" : active ? undefined : "gray"}
              style={{ whiteSpace: "nowrap" }}
            >
              {label}
            </Text>
            {i < STEPS.length - 1 && (
              <Box
                style={{
                  width: 16,
                  height: 1,
                  background: done ? "var(--green-7)" : "var(--gray-5)",
                  flexShrink: 0,
                }}
              />
            )}
          </Flex>
        );
      })}
    </Flex>
  );
}

function DropZone({
  file,
  onChange,
  disabled,
}: {
  file: File | null;
  onChange: (f: File) => void;
  disabled: boolean;
}) {
  const inputRef = useRef<HTMLInputElement>(null);
  const [dragging, setDragging] = useState(false);

  const handleDrop = useCallback(
    (e: React.DragEvent) => {
      e.preventDefault();
      setDragging(false);
      if (disabled) return;
      const dropped = e.dataTransfer.files[0];
      if (dropped?.type === "application/pdf") onChange(dropped);
    },
    [disabled, onChange],
  );

  return (
    <Box
      onClick={() => !disabled && inputRef.current?.click()}
      onDragOver={(e) => { e.preventDefault(); if (!disabled) setDragging(true); }}
      onDragLeave={() => setDragging(false)}
      onDrop={handleDrop}
      style={{
        border: `2px dashed ${dragging ? "var(--accent-9)" : file ? "var(--green-8)" : "var(--gray-6)"}`,
        borderRadius: 10,
        padding: "28px 20px",
        textAlign: "center",
        cursor: disabled ? "not-allowed" : "pointer",
        background: dragging
          ? "var(--accent-2)"
          : file
            ? "var(--green-2)"
            : "var(--gray-2)",
        transition: "all 0.15s ease",
        opacity: disabled ? 0.6 : 1,
      }}
    >
      <input
        ref={inputRef}
        type="file"
        accept="application/pdf,.pdf"
        style={{ display: "none" }}
        onChange={(e) => {
          const f = e.target.files?.[0];
          if (f) onChange(f);
        }}
        disabled={disabled}
      />
      <Flex direction="column" align="center" gap="2">
        {file ? (
          <FileIcon width={28} height={28} color="var(--green-9)" />
        ) : (
          <UploadIcon width={28} height={28} color="var(--gray-9)" />
        )}
        {file ? (
          <>
            <Text size="2" weight="medium" color="green">
              {file.name}
            </Text>
            <Text size="1" color="gray">
              {(file.size / 1024).toFixed(1)} KB — click to change
            </Text>
          </>
        ) : (
          <>
            <Text size="2" weight="medium">
              Drop your PDF here or click to browse
            </Text>
            <Text size="1" color="gray">
              PDF files only · max 20 pages
            </Text>
          </>
        )}
      </Flex>
    </Box>
  );
}

function MarkdownAnswer({ text }: { text: string }) {
  // Simple markdown: bold, bullet lines, line breaks
  const lines = text.split("\n");
  return (
    <Flex direction="column" gap="1">
      {lines.map((line, i) => {
        const trimmed = line.trimStart();
        const isBullet = trimmed.startsWith("- ") || trimmed.startsWith("• ") || trimmed.startsWith("* ");
        const content = isBullet ? trimmed.slice(2) : line;
        const parts = content.split(/(\*\*[^*]+\*\*)/g);
        const rendered = parts.map((p, j) =>
          p.startsWith("**") && p.endsWith("**") ? (
            <Text key={j} weight="bold">{p.slice(2, -2)}</Text>
          ) : (
            <span key={j}>{p}</span>
          ),
        );
        if (!line.trim()) return <Box key={i} style={{ height: 6 }} />;
        return (
          <Text key={i} size="2" style={{ lineHeight: "1.65" }}>
            {isBullet && <span style={{ marginRight: 6 }}>•</span>}
            {rendered}
          </Text>
        );
      })}
    </Flex>
  );
}

